package com.courassistant.java;

import android.app.PendingIntent;
import android.content.BroadcastReceiver;
import android.content.Context;
import android.content.Intent;
import android.provider.Telephony;
import android.util.Log;
import androidx.core.app.NotificationCompat;
import androidx.core.app.NotificationManagerCompat;
import com.shanfuchun.courtassistant.App;
import com.shanfuchun.courtassistant.R;
import com.shanfuchun.courtassistant.data.SmsRecord;
import com.shanfuchun.courtassistant.ui.MainActivity;
import java.util.Map;
import java.util.HashMap;
import java.util.List;
import java.util.ArrayList;
import kotlinx.coroutines.CoroutineScope;
import kotlinx.coroutines.Dispatchers;
import kotlinx.coroutines.launch;

/**
 * 短信广播接收器
 * 监听 SMS_RECEIVED 广播，过滤法院相关短信
 */
public class SmsReceiver extends BroadcastReceiver {
    private static final String TAG = "SmsReceiver";
    private static final String CHANNEL_ID = "court_sms_channel";

    // 法院相关关键词
    private static final String[] COURT_KEYWORDS = {
        "法院", "开庭", "传票", "案号", "诉讼", "审判",
        "中级人民法院", "基层人民法院", "高级人民法院"
    };

    @Override
    public void onReceive(Context context, Intent intent) {
        if (intent.getAction() == null ||
            !intent.getAction().equals(Telephony.Sms.Intents.SMS_RECEIVED_ACTION)) {
            return;
        }

        List<android.telephony.SmsMessage> messages = Telephony.Sms.Intents.getMessagesFromIntent(intent);
        if (messages == null || messages.isEmpty()) {
            return;
        }

        // 按发送者分组短信
        Map<String, StringBuilder> groupedMessages = new HashMap<>();
        for (android.telephony.SmsMessage message : messages) {
            String sender = message.getDisplayOriginatingAddress();
            String body = message.getDisplayMessageBody();

            if (sender == null || body == null) {
                continue;
            }

            // 检查是否是法院相关短信
            if (!isCourtRelatedSms(body)) {
                continue;
            }

            groupedMessages
                .computeIfAbsent(sender, k -> new StringBuilder())
                .append(body);
        }

        // 处理分组后的短信
        App app = (App) context.getApplicationContext();
        for (Map.Entry<String, StringBuilder> entry : groupedMessages.entrySet()) {
            String sender = entry.getKey();
            String content = entry.getValue().toString();

            processSms(context, app, sender, content);
        }
    }

    /**
     * 判断短信是否与法院相关
     */
    private boolean isCourtRelatedSms(String content) {
        if (content == null || content.isEmpty()) {
            return false;
        }

        for (String keyword : COURT_KEYWORDS) {
            if (content.contains(keyword)) {
                Log.d(TAG, "Found court keyword: " + keyword);
                return true;
            }
        }

        // 检查是否包含URL（可能是法院短信中的链接）
        if (content.contains("http://") || content.contains("https://")) {
            Log.d(TAG, "Found URL in SMS");
            return true;
        }

        return false;
    }

    /**
     * 处理短信并启动服务
     */
    private void processSms(Context context, App app, String sender, String content) {
        long receiveTime = System.currentTimeMillis();

        // 提取URL
        List<String> urls = SmsParser.extractUrls(content);
        boolean hasLink = !urls.isEmpty();

        // 创建短信记录
        SmsRecord record = new SmsRecord(
            0, // id，将由数据库自动生成
            sender,
            content,
            receiveTime,
            hasLink,
            0, // parseStatus: 0-未解析, 1-已解析
            new ArrayList<>(), // documentIds
            false, // hasSummons
            "", // courtName
            "", // partyName
            receiveTime // createdAt
        );

        // 在协程中保存到数据库并启动服务处理
        CoroutineScope scope = CoroutineScope(Dispatchers.getIO());
        scope.launch(() -> {
            try {
                long id = app.getDb().smsDao().insert(record);

                if (id > 0) {
                    Log.d(TAG, "SMS saved with id: " + id);

                    // 启动 SmsMonitorService 处理
                    Intent serviceIntent = new Intent(context, SmsMonitorService.class);
                    serviceIntent.putExtra("sms_id", id);
                    serviceIntent.putExtra("sms_sender", sender);
                    serviceIntent.putExtra("sms_body", content);
                    context.startService(serviceIntent);

                    // 显示通知
                    showNotification(context, content);
                }
            } catch (Exception e) {
                Log.e(TAG, "Error saving SMS", e);
            }
        });
    }

    /**
     * 显示法院短信通知
     */
    private void showNotification(Context context, String content) {
        int notificationId = (int) (System.currentTimeMillis() % Integer.MAX_VALUE);

        // 打开应用的 Intent
        PendingIntent openIntent = PendingIntent.getActivity(
            context,
            0,
            new Intent(context, MainActivity.class)
                .addFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TOP),
            PendingIntent.FLAG_UPDATE_CURRENT | PendingIntent.FLAG_IMMUTABLE
        );

        // 构建通知
        NotificationCompat.Builder builder = new NotificationCompat.Builder(context, App.CHANNEL_ID)
            .setSmallIcon(R.mipmap.ic_launcher)
            .setContentTitle("法院短信通知")
            .setContentText(content.length() > 60 ? content.substring(0, 60) + "..." : content)
            .setStyle(new NotificationCompat.BigTextStyle().bigText(content))
            .setContentIntent(openIntent)
            .setAutoCancel(true)
            .addAction(0, "查看详情", openIntent);

        try {
            NotificationManagerCompat.from(context).notify(notificationId, builder.build());
        } catch (SecurityException e) {
            Log.e(TAG, "Permission denied for notification", e);
        }
    }
}

package com.courassistant.java;

import android.app.Notification;
import android.app.NotificationChannel;
import android.app.NotificationManager;
import android.app.Service;
import android.content.Context;
import android.content.Intent;
import android.os.IBinder;
import android.util.Log;
import androidx.core.app.NotificationCompat;
import com.shanfuchun.courtassistant.App;
import com.shanfuchun.courtassistant.R;
import com.shanfuchun.courtassistant.data.AppDatabase;
import com.shanfuchun.courtassistant.data.SmsRecord;
import com.shanfuchun.courtassistant.service.CalendarHelper;
import com.shanfuchun.courtassistant.service.PdfDownloader;
import kotlinx.coroutines.CoroutineScope;
import kotlinx.coroutines.Dispatchers;
import kotlinx.coroutines.Job;
import kotlinx.coroutines.launch;
import java.util.List;

/**
 * 短信监控前台服务
 * 负责解析新收到的短信并保存到数据库
 */
public class SmsMonitorService extends Service {
    private static final String TAG = "SmsMonitorService";
    private static final String CHANNEL_ID = "sms_monitor_service_channel";
    private static final int NOTIFICATION_ID = 1001;

    private AppDatabase database;
    private Job processingJob;
    private CoroutineScope serviceScope;

    @Override
    public void onCreate() {
        super.onCreate();
        Log.d(TAG, "SmsMonitorService created");

        App app = (App) getApplicationContext();
        database = app.getDb();
        serviceScope = CoroutineScope(Dispatchers.getIO() + new Job());

        // 创建前台服务通知
        createNotificationChannel();
        startForeground(NOTIFICATION_ID, createNotification());
    }

    @Override
    public int onStartCommand(Intent intent, int flags, int startId) {
        if (intent == null) {
            return START_NOT_STICKY;
        }

        long smsId = intent.getLongExtra("sms_id", 0);
        String sender = intent.getStringExtra("sms_sender");
        String body = intent.getStringExtra("sms_body");

        Log.d(TAG, "Processing SMS: id=" + smsId + ", sender=" + sender);

        if (smsId > 0 && body != null) {
            processSms(smsId, sender, body);
        }

        return START_NOT_STICKY;
    }

    /**
     * 处理短信：解析内容、保存到数据库、触发WebView下载
     */
    private void processSms(long smsId, String sender, String body) {
        processingJob = serviceScope.launch(() -> {
            try {
                Log.d(TAG, "Starting to parse SMS id=" + smsId);

                // 1. 调用 SmsParser 解析内容
                SmsParser.ParseResult parseResult = SmsParser.parse(body);

                Log.d(TAG, "Parse result: " +
                    "caseNo=" + parseResult.getCaseNo() + ", " +
                    "courtName=" + parseResult.getCourtName() + ", " +
                    "hearingTime=" + parseResult.getHearingTime() + ", " +
                    "hasSummons=" + parseResult.isHasSummons() + ", " +
                    "urls=" + parseResult.getUrls().size());

                // 2. 更新短信记录
                SmsRecord originalRecord = database.smsDao().getById(smsId);
                if (originalRecord != null) {
                    SmsRecord updatedRecord = new SmsRecord(
                        originalRecord.getId(),
                        originalRecord.getSender(),
                        originalRecord.getBody(),
                        originalRecord.getReceiveTime(),
                        originalRecord.getHasLink(),
                        1, // parseStatus: 已解析
                        parseResult.getUrls(),
                        parseResult.isHasSummons(),
                        parseResult.getCourtName(),
                        parseResult.getPartyName(),
                        originalRecord.getCreatedAt()
                    );

                    database.smsDao().update(updatedRecord);
                    Log.d(TAG, "Updated SMS record with parsed data");
                }

                // 3. 同步开庭信息到日历
                if (parseResult.getHearingTime() > 0) {
                    try {
                        boolean synced = CalendarHelper.syncHearing(
                            this,
                            database,
                            parseResult.toHearingInfo(),
                            smsId,
                            "sms",
                            body
                        );
                        Log.d(TAG, "Calendar sync result: " + synced);
                    } catch (Exception e) {
                        Log.e(TAG, "Error syncing to calendar", e);
                    }
                }

                // 4. 提取链接并触发下载
                List<String> urls = parseResult.getUrls();
                if (!urls.isEmpty()) {
                    handleUrlDownloads(this, smsId, urls);
                }

                Log.d(TAG, "SMS processing completed for id=" + smsId);

                // 处理完成后停止服务
                stopSelf();

            } catch (Exception e) {
                Log.e(TAG, "Error processing SMS", e);
                stopSelf();
            }
        });
    }

    /**
     * 处理URL下载
     * 判断是否需要WebView渲染后下载
     */
    private void handleUrlDownloads(Context context, long smsId, List<String> urls) {
        boolean webViewNeeded = false;

        for (String url : urls) {
            try {
                // 检查是否是SPA页面（需要WebView渲染）
                boolean isSpa = url.contains("#") ||
                               url.contains("/#/") ||
                               url.contains("zxfw.court.gov.cn") ||
                               url.contains("wenshu.court.gov.cn");

                if (isSpa) {
                    Log.d(TAG, "SPA page detected, will use WebView: " + url);
                    webViewNeeded = true;
                    // 保存为待下载记录
                    PdfDownloader.savePendingUrlSync(database, smsId, url, "需要WebView加载");
                } else {
                    // 尝试直接下载
                    Log.d(TAG, "Attempting direct download from: " + url);
                    PdfDownloader.downloadFromUrls(context, database, smsId, urls);
                }
            } catch (Exception e) {
                Log.e(TAG, "Error processing URL: " + url, e);
                webViewNeeded = true;
            }
        }

        // 如果有需要WebView的URL，启动WebView处理
        if (webViewNeeded) {
            launchWebViewActivity(context, urls);
        }
    }

    /**
     * 启动WebViewActivity进行下载
     */
    private void launchWebViewActivity(Context context, List<String> urls) {
        for (String url : urls) {
            if (url.contains("#") || url.contains("/#/") || url.contains("zxfw.court.gov.cn")) {
                Intent intent = new Intent(context, com.shanfuchun.courtassistant.ui.WebViewActivity.class);
                intent.putExtra("url", url);
                intent.putExtra("smsId", 0); // 将从URL或其他方式识别
                intent.putExtra("autoMode", true);
                intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK);

                try {
                    context.startActivity(intent);
                    Log.d(TAG, "Launched WebView for: " + url);
                    break; // 只启动第一个需要WebView的URL
                } catch (Exception e) {
                    Log.e(TAG, "Failed to launch WebView", e);
                }
            }
        }
    }

    /**
     * 创建通知渠道
     */
    private void createNotificationChannel() {
        NotificationChannel channel = new NotificationChannel(
            CHANNEL_ID,
            "短信监控服务",
            NotificationManager.IMPORTANCE_LOW
        );
        channel.setDescription("正在监控和处理法院短信");

        NotificationManager manager = getSystemService(NotificationManager.class);
        if (manager != null) {
            manager.createNotificationChannel(channel);
        }
    }

    /**
     * 创建前台服务通知
     */
    private Notification createNotification() {
        return new NotificationCompat.Builder(this, CHANNEL_ID)
            .setContentTitle("法院短信监控")
            .setContentText("正在处理新收到的法院短信...")
            .setSmallIcon(R.mipmap.ic_launcher)
            .setPriority(NotificationCompat.PRIORITY_LOW)
            .build();
    }

    @Override
    public IBinder onBind(Intent intent) {
        return null;
    }

    @Override
    public void onDestroy() {
        super.onDestroy();
        Log.d(TAG, "SmsMonitorService destroyed");

        if (processingJob != null) {
            processingJob.cancel();
        }
    }
}

package com.courassistant.java;

import android.util.Log;
import java.util.ArrayList;
import java.util.Calendar;
import java.util.TimeZone;
import java.util.List;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

/**
 * 短信内容解析器
 * 使用正则表达式提取法院短信中的关键信息
 */
public class SmsParser {
    private static final String TAG = "SmsParser";

    // 案号正则：支持 (2024)京01民初123号 格式
    private static final Pattern CASE_NO_PATTERN = Pattern.compile(
        "[（(]\\s*\\d{4}\\s*[）)]\\s*" +
        "[京津沪渝冀豫云辽黑湘皖鲁新苏浙赣鄂桂甘晋蒙陕吉闽贵粤川青藏琼宁]\\s*" +
        "\\d{2,4}\\s*[\\u4e00-\\u9fa5]{1,4}\\s*[\\u4e00-\\u9fa5]{0,2}\\d+\\s*号"
    );

    // 法院名称正则
    private static final Pattern COURT_NAME_PATTERN = Pattern.compile(
        "[\\u4e00-\\u9fa5]+(?:人民法院|人民法庭|人\\s*法院|仲裁委员会|仲裁院)"
    );

    // 开庭时间正则（多种格式）
    private static final List<Pattern> TIME_PATTERNS = new ArrayList<>();
    static {
        // 2024年3月15日上午9:30
        TIME_PATTERNS.add(Pattern.compile(
            "(\\d{4})\\s*年\\s*(\\d{1,2})\\s*月\\s*(\\d{1,2})\\s*日(?:\\s*(上午|下午|晚上))?\\s*(\\d{1,2})\\s*[：:]\\s*(\\d{1,2})"
        ));
        // 2024年3月15日 9时30分
        TIME_PATTERNS.add(Pattern.compile(
            "(\\d{4})\\s*年\\s*(\\d{1,2})\\s*月\\s*(\\d{1,2})\\s*日\\s*(\\d{1,2})\\s*时\\s*(\\d{1,2})\\s*分"
        ));
        // 2024-03-15 09:30
        TIME_PATTERNS.add(Pattern.compile(
            "(\\d{4})[-/](\\d{1,2})[-/](\\d{1,2})\\s+(\\d{1,2}):(\\d{2})"
        ));
        // 定于2024年3月15日9时30分
        TIME_PATTERNS.add(Pattern.compile(
            "定于[\\s\\S]{0,10}?(\\d{4})\\s*年\\s*(\\d{1,2})\\s*月\\s*(\\d{1,2})\\s*日\\s*(\\d{1,2})\\s*时\\s*(\\d{1,2})\\s*分"
        ));
        // 3月15日9时30分（无年份）
        TIME_PATTERNS.add(Pattern.compile(
            "(?<!\\d)(\\d{1,2})\\s*月\\s*(\\d{1,2})\\s*日\\s*(\\d{1,2})\\s*时\\s*(\\d{1,2})\\s*分"
        ));
    }

    // 当事人名称正则
    private static final List<Pattern> PARTY_PATTERNS = new ArrayList<>();
    static {
        PARTY_PATTERNS.add(Pattern.compile("被传唤人[\\s：:]*([\\u4e00-\\u9fa5()（）\\d]{2,30})"));
        PARTY_PATTERNS.add(Pattern.compile("(?:被告|原告|当事人|被申请人|申请人)[\\s：:]*([\\u4e00-\\u9fa5()（）\\d]{2,30})"));
    }

    // URL链接正则
    private static final Pattern URL_PATTERN = Pattern.compile(
        "https?://[\\w\\-._~:/?#\\[\\]@!$&'()*+,;=%]+"
    );

    // 传票关键词
    private static final String[] SUMMONS_KEYWORDS = {
        "传票", "出庭", "应到", "开庭通知", "出庭通知"
    };

    /**
     * 解析结果类
     */
    public static class ParseResult {
        private String caseNo = "";
        private long hearingTime = 0;
        private String courtName = "";
        private String partyName = "";
        private List<String> urls = new ArrayList<>();
        private boolean hasSummons = false;
        private String location = "";

        public String getCaseNo() { return caseNo; }
        public void setCaseNo(String caseNo) { this.caseNo = caseNo; }

        public long getHearingTime() { return hearingTime; }
        public void setHearingTime(long hearingTime) { this.hearingTime = hearingTime; }

        public String getCourtName() { return courtName; }
        public void setCourtName(String courtName) { this.courtName = courtName; }

        public String getPartyName() { return partyName; }
        public void setPartyName(String partyName) { this.partyName = partyName; }

        public List<String> getUrls() { return urls; }
        public void setUrls(List<String> urls) { this.urls = urls; }

        public boolean isHasSummons() { return hasSummons; }
        public void setHasSummons(boolean hasSummons) { this.hasSummons = hasSummons; }

        public String getLocation() { return location; }
        public void setLocation(String location) { this.location = location; }

        /**
         * 转换为 HearingInfo 对象
         */
        public com.shanfuchun.courtassistant.service.HearingInfo toHearingInfo() {
            return new com.shanfuchun.courtassistant.service.HearingInfo(
                hearingTime,
                courtName,
                caseNo,
                location,
                partyName,
                "" // judge
            );
        }
    }

    /**
     * 解析短信内容
     */
    public static ParseResult parse(String content) {
        ParseResult result = new ParseResult();

        if (content == null || content.isEmpty()) {
            return result;
        }

        try {
            // 清理OCR噪声
            String cleaned = cleanOcrNoise(content);

            // 提取案号
            result.setCaseNo(extractCaseNo(cleaned));

            // 提取开庭时间
            result.setHearingTime(extractHearingTime(cleaned));

            // 提取法院名称
            result.setCourtName(extractCourtName(cleaned));

            // 提取当事人名称
            result.setPartyName(extractPartyName(cleaned));

            // 提取URL
            result.setUrls(extractUrls(cleaned));

            // 判断是否包含传票关键词
            result.setHasSummons(checkSummonsKeywords(cleaned));

            Log.d(TAG, "Parse completed: " +
                "caseNo=" + result.getCaseNo() + ", " +
                "courtName=" + result.getCourtName() + ", " +
                "hearingTime=" + result.getHearingTime() + ", " +
                "partyName=" + result.getPartyName() + ", " +
                "urls=" + result.getUrls().size() + ", " +
                "hasSummons=" + result.isHasSummons());

        } catch (Exception e) {
            Log.e(TAG, "Error parsing SMS", e);
        }

        return result;
    }

    /**
     * 提取案号
     */
    private static String extractCaseNo(String content) {
        Matcher matcher = CASE_NO_PATTERN.matcher(content);
        if (matcher.find()) {
            return matcher.group().replaceAll("\\s+", "");
        }

        // 尝试宽松模式（无括号）
        Pattern loosePattern = Pattern.compile(
            "\\b(\\d{4})[\\s]*[京津沪渝冀豫云辽黑湘皖鲁新苏浙赣鄂桂甘晋蒙陕吉闽贵粤川青藏琼宁]" +
            "[\\s]*\\d{2,4}[\\s]*[\\u4e00-\\u9fa5]{1,4}\\d+[\\s]*号"
        );
        Matcher looseMatcher = loosePattern.matcher(content);
        if (looseMatcher.find()) {
            return "(" + looseMatcher.group().replaceAll("\\s+", "").replaceFirst("^(\\d{4})", "$1)");
        }

        return "";
    }

    /**
     * 提取开庭时间
     */
    private static long extractHearingTime(String content) {
        Calendar cal = Calendar.getInstance(TimeZone.getTimeZone("Asia/Shanghai"));

        for (int i = 0; i < TIME_PATTERNS.size(); i++) {
            Matcher matcher = TIME_PATTERNS.get(i).matcher(content);
            if (matcher.find()) {
                try {
                    long time = parseTime(matcher, i, cal);
                    if (time > 0) {
                        return time;
                    }
                } catch (Exception e) {
                    Log.w(TAG, "Failed to parse time with pattern " + i);
                }
            }
        }

        return 0;
    }

    /**
     * 解析时间匹配结果
     */
    private static long parseTime(Matcher matcher, int patternIdx, Calendar cal) {
        try {
            int year, month, day, hour, minute;

            switch (patternIdx) {
                case 0: // 2024年3月15日上午9:30
                    year = Integer.parseInt(matcher.group(1));
                    month = Integer.parseInt(matcher.group(2));
                    day = Integer.parseInt(matcher.group(3));
                    hour = Integer.parseInt(matcher.group(5));
                    minute = Integer.parseInt(matcher.group(6));

                    // 处理上午/下午
                    String period = matcher.group(4);
                    if (period != null) {
                        if (period.equals("下午") || period.equals("晚上")) {
                            if (hour < 12) hour += 12;
                        } else if (period.equals("上午") && hour == 12) {
                            hour = 0;
                        }
                    }
                    break;

                case 1: // 2024年3月15日9时30分
                case 2: // 2024-03-15 09:30
                case 3: // 定于2024年3月15日9时30分
                    year = Integer.parseInt(matcher.group(1));
                    month = Integer.parseInt(matcher.group(2));
                    day = Integer.parseInt(matcher.group(3));
                    hour = Integer.parseInt(matcher.group(4));
                    minute = Integer.parseInt(matcher.group(5));
                    break;

                case 4: // 3月15日9时30分（无年份）
                    month = Integer.parseInt(matcher.group(1));
                    day = Integer.parseInt(matcher.group(2));
                    hour = Integer.parseInt(matcher.group(3));
                    minute = Integer.parseInt(matcher.group(4));
                    year = cal.get(Calendar.YEAR);
                    break;

                default:
                    return 0;
            }

            // 验证日期时间合法性
            if (month < 1 || month > 12 || day < 1 || day > 31 ||
                hour < 0 || hour > 23 || minute < 0 || minute > 59) {
                return 0;
            }

            cal.set(year, month - 1, day, hour, minute, 0);
            cal.set(Calendar.MILLISECOND, 0);

            return cal.getTimeInMillis();

        } catch (Exception e) {
            Log.e(TAG, "Error parsing time", e);
            return 0;
        }
    }

    /**
     * 提取法院名称
     */
    private static String extractCourtName(String content) {
        Matcher matcher = COURT_NAME_PATTERN.matcher(content);
        if (matcher.find()) {
            String fullName = matcher.group();
            return simplifyCourtName(fullName);
        }
        return "";
    }

    /**
     * 简化法院名称
     */
    private static String simplifyCourtName(String fullName) {
        if (fullName.contains("最高人民法院")) {
            return "最高人民法院";
        } else if (fullName.contains("高级人民法院")) {
            return fullName.substring(0, 2) + "高院";
        } else if (fullName.contains("中级人民法院")) {
            return fullName.substring(0, 2) + "中院";
        } else if (fullName.contains("区人民法院") || fullName.contains("县人民法院")) {
            return fullName.substring(0, 2) + "法院";
        } else if (fullName.contains("人民法庭")) {
            return fullName.substring(0, 2) + "法庭";
        } else if (fullName.contains("仲裁委员会")) {
            return fullName.substring(0, 2) + "仲裁委";
        }
        return fullName;
    }

    /**
     * 提取当事人名称
     */
    private static String extractPartyName(String content) {
        for (Pattern pattern : PARTY_PATTERNS) {
            Matcher matcher = pattern.matcher(content);
            if (matcher.find()) {
                String name = matcher.group(1);
                if (name != null && !name.isEmpty()) {
                    // 过滤掉误匹配的关键词
                    if (!name.contains("传票") && !name.contains("经传") && !name.contains("传唤")) {
                        return name.trim();
                    }
                }
            }
        }
        return "";
    }

    /**
     * 提取URL列表
     */
    public static List<String> extractUrls(String content) {
        List<String> urls = new ArrayList<>();
        Matcher matcher = URL_PATTERN.matcher(content);

        while (matcher.find()) {
            String url = matcher.group();
            if (url != null && !url.isEmpty()) {
                urls.add(url);
            }
        }

        return urls;
    }

    /**
     * 检查是否包含传票关键词
     */
    private static boolean checkSummonsKeywords(String content) {
        for (String keyword : SUMMONS_KEYWORDS) {
            if (content.contains(keyword)) {
                return true;
            }
        }
        return false;
    }

    /**
     * 清理OCR噪声
     */
    private static String cleanOcrNoise(String text) {
        // 替换换行符为空格
        String cleaned = text.replace("\r\n", " ").replace("\n", " ").replace("\r", " ");

        // 移除多余的空格
        cleaned = cleaned.replaceAll("\\s+", " ").trim();

        return cleaned;
    }
}

package com.courassistant.java;

import android.util.Log;
import com.shanfuchun.courtassistant.domain.model.Summons;
import com.shanfuchun.courtassistant.domain.model.Sms;
import java.util.List;

/**
 * 案件信息提取器
 * 从解析结果中提取结构化案件信息
 */
public class CaseInfoExtractor {
    private static final String TAG = "CaseInfoExtractor";

    /**
     * CourtCase 数据类
     */
    public static class CourtCase {
        private long id;
        private String caseNo;           // 案号
        private String courtName;        // 法院名称
        private long hearingTime;        // 开庭时间
        private String location;         // 开庭地点
        private String partyName;        // 当事人名称
        private String judgeName;        // 审判员
        private String caseType;         // 案件类型
        private String plaintiff;        // 原告
        private String defendant;        // 被告
        private float confidence;        // 置信度
        private long smsId;              // 关联的短信ID
        private long documentId;         // 关联的文档ID

        public CourtCase() {
            this.confidence = 0.0f;
            this.smsId = 0;
            this.documentId = 0;
        }

        // Getters
        public long getId() { return id; }
        public String getCaseNo() { return caseNo; }
        public String getCourtName() { return courtName; }
        public long getHearingTime() { return hearingTime; }
        public String getLocation() { return location; }
        public String getPartyName() { return partyName; }
        public String getJudgeName() { return judgeName; }
        public String getCaseType() { return caseType; }
        public String getPlaintiff() { return plaintiff; }
        public String getDefendant() { return defendant; }
        public float getConfidence() { return confidence; }
        public long getSmsId() { return smsId; }
        public long getDocumentId() { return documentId; }

        // Setters
        public void setId(long id) { this.id = id; }
        public void setCaseNo(String caseNo) { this.caseNo = caseNo; }
        public void setCourtName(String courtName) { this.courtName = courtName; }
        public void setHearingTime(long hearingTime) { this.hearingTime = hearingTime; }
        public void setLocation(String location) { this.location = location; }
        public void setPartyName(String partyName) { this.partyName = partyName; }
        public void setJudgeName(String judgeName) { this.judgeName = judgeName; }
        public void setCaseType(String caseType) { this.caseType = caseType; }
        public void setPlaintiff(String plaintiff) { this.plaintiff = plaintiff; }
        public void setDefendant(String defendant) { this.defendant = defendant; }
        public void setConfidence(float confidence) { this.confidence = confidence; }
        public void setSmsId(long smsId) { this.smsId = smsId; }
        public void setDocumentId(long documentId) { this.documentId = documentId; }

        /**
         * 判断案件信息是否完整
         */
        public boolean isComplete() {
            return !caseNo.isEmpty() &&
                   !courtName.isEmpty() &&
                   hearingTime > 0 &&
                   !partyName.isEmpty();
        }

        /**
         * 计算信息完整度（0-1）
         */
        public float getCompleteness() {
            int fields = 0;
            int filled = 0;

            fields++; if (!caseNo.isEmpty()) filled++;
            fields++; if (!courtName.isEmpty()) filled++;
            fields++; if (hearingTime > 0) filled++;
            fields++; if (!location.isEmpty()) filled++;
            fields++; if (!partyName.isEmpty()) filled++;
            fields++; if (!judgeName.isEmpty()) filled++;
            fields++; if (!caseType.isEmpty()) filled++;
            fields++; if (!plaintiff.isEmpty()) filled++;
            fields++; if (!defendant.isEmpty()) filled++;

            return fields > 0 ? (float) filled / fields : 0.0f;
        }

        @Override
        public String toString() {
            return "CourtCase{" +
                    "id=" + id +
                    ", caseNo='" + caseNo + '\'' +
                    ", courtName='" + courtName + '\'' +
                    ", hearingTime=" + hearingTime +
                    ", location='" + location + '\'' +
                    ", partyName='" + partyName + '\'' +
                    ", judgeName='" + judgeName + '\'' +
                    ", caseType='" + caseType + '\'' +
                    ", plaintiff='" + plaintiff + '\'' +
                    ", defendant='" + defendant + '\'' +
                    ", confidence=" + confidence +
                    ", completeness=" + getCompleteness() +
                    '}';
        }
    }

    /**
     * 从短信解析结果构造 CourtCase 对象
     */
    public static CourtCase extractFromSms(Sms sms, SmsParser.ParseResult parseResult) {
        CourtCase courtCase = new CourtCase();

        if (sms == null) {
            Log.w(TAG, "SMS is null, cannot extract CourtCase");
            return courtCase;
        }

        courtCase.setSmsId(sms.getId());
        courtCase.setCaseNo(parseResult.getCaseNo());
        courtCase.setCourtName(parseResult.getCourtName());
        courtCase.setHearingTime(parseResult.getHearingTime());
        courtCase.setLocation(parseResult.getLocation());
        courtCase.setPartyName(parseResult.getPartyName());

        // 根据提取的信息计算置信度
        courtCase.setConfidence(calculateConfidence(parseResult));

        // 尝试从案号中推断案件类型
        courtCase.setCaseType(inferCaseType(parseResult.getCaseNo()));

        Log.d(TAG, "Extracted CourtCase from SMS: " + courtCase.toString());

        return courtCase;
    }

    /**
     * 从原始文本直接提取案件信息
     */
    public static CourtCase extractFromText(String text, long smsId) {
        CourtCase courtCase = new CourtCase();

        if (text == null || text.isEmpty()) {
            Log.w(TAG, "Text is empty, cannot extract CourtCase");
            return courtCase;
        }

        // 使用 SmsParser 解析
        SmsParser.ParseResult parseResult = SmsParser.parse(text);

        courtCase.setSmsId(smsId);
        courtCase.setCaseNo(parseResult.getCaseNo());
        courtCase.setCourtName(parseResult.getCourtName());
        courtCase.setHearingTime(parseResult.getHearingTime());
        courtCase.setLocation(parseResult.getLocation());
        courtCase.setPartyName(parseResult.getPartyName());
        courtCase.setConfidence(calculateConfidence(parseResult));
        courtCase.setCaseType(inferCaseType(parseResult.getCaseNo()));

        Log.d(TAG, "Extracted CourtCase from text: " + courtCase.toString());

        return courtCase;
    }

    /**
     * 转换为 Summons 领域模型
     */
    public static Summons toSummons(CourtCase courtCase, long documentId) {
        return new Summons(
            courtCase.getId(),
            documentId,
            courtCase.getCaseNo(),
            courtCase.getCourtName(),
            courtCase.getHearingTime(),
            courtCase.getLocation(),
            courtCase.getPartyName(),
            courtCase.getConfidence()
        );
    }

    /**
     * 从案号推断案件类型
     */
    private static String inferCaseType(String caseNo) {
        if (caseNo == null || caseNo.isEmpty()) {
            return "未知";
        }

        if (caseNo.contains("民初") || caseNo.contains("民终")) {
            return "民事";
        } else if (caseNo.contains("刑初") || caseNo.contains("刑终")) {
            return "刑事";
        } else if (caseNo.contains("行初") || caseNo.contains("行终")) {
            return "行政";
        } else if (caseNo.contains("执")) {
            return "执行";
        } else if (caseNo.contains("赔")) {
            return "赔偿";
        } else if (caseNo.contains("商")) {
            return "商事";
        } else if (caseNo.contains("知")) {
            return "知识产权";
        }

        return "其他";
    }

    /**
     * 计算置信度
     * 基于提取的字段完整性
     */
    private static float calculateConfidence(SmsParser.ParseResult parseResult) {
        float confidence = 0.0f;
        int totalFields = 5;
        int filledFields = 0;

        if (!parseResult.getCaseNo().isEmpty()) filledFields++;
        if (!parseResult.getCourtName().isEmpty()) filledFields++;
        if (parseResult.getHearingTime() > 0) filledFields++;
        if (!parseResult.getPartyName().isEmpty()) filledFields++;
        if (!parseResult.getUrls().isEmpty()) filledFields++;

        confidence = (float) filledFields / totalFields;

        // 如果包含传票关键词，提高置信度
        if (parseResult.isHasSummons()) {
            confidence = Math.min(1.0f, confidence + 0.1f);
        }

        return confidence;
    }

    /**
     * 合并两个 CourtCase 对象
     * 优先保留信息更完整的字段
     */
    public static CourtCase merge(CourtCase primary, CourtCase secondary) {
        CourtCase merged = new CourtCase();

        // 基础信息
        merged.setId(primary.getId());
        merged.setSmsId(primary.getSmsId() > 0 ? primary.getSmsId() : secondary.getSmsId());
        merged.setDocumentId(primary.getDocumentId() > 0 ? primary.getDocumentId() : secondary.getDocumentId());

        // 选择置信度更高的字段
        merged.setCaseNo(
            primary.getCaseNo().isEmpty() ? secondary.getCaseNo() : primary.getCaseNo()
        );
        merged.setCourtName(
            primary.getCourtName().isEmpty() ? secondary.getCourtName() : primary.getCourtName()
        );
        merged.setHearingTime(
            primary.getHearingTime() > 0 ? primary.getHearingTime() : secondary.getHearingTime()
        );
        merged.setLocation(
            primary.getLocation().isEmpty() ? secondary.getLocation() : primary.getLocation()
        );
        merged.setPartyName(
            primary.getPartyName().isEmpty() ? secondary.getPartyName() : primary.getPartyName()
        );
        merged.setJudgeName(
            primary.getJudgeName().isEmpty() ? secondary.getJudgeName() : primary.getJudgeName()
        );
        merged.setCaseType(
            primary.getCaseType().isEmpty() ? secondary.getCaseType() : primary.getCaseType()
        );
        merged.setPlaintiff(
            primary.getPlaintiff().isEmpty() ? secondary.getPlaintiff() : primary.getPlaintiff()
        );
        merged.setDefendant(
            primary.getDefendant().isEmpty() ? secondary.getDefendant() : primary.getDefendant()
        );

        // 取平均置信度
        merged.setConfidence((primary.getConfidence() + secondary.getConfidence()) / 2.0f);

        return merged;
    }

    /**
     * 验证案件信息的有效性
     */
    public static boolean isValid(CourtCase courtCase) {
        if (courtCase == null) {
            return false;
        }

        // 至少需要有案号或开庭时间
        if (courtCase.getCaseNo().isEmpty() && courtCase.getHearingTime() <= 0) {
            return false;
        }

        // 如果有开庭时间，必须是未来的时间
        if (courtCase.getHearingTime() > 0) {
            long currentTime = System.currentTimeMillis();
            if (courtCase.getHearingTime() < currentTime) {
                Log.w(TAG, "Hearing time is in the past: " + courtCase.getHearingTime());
                // 仍然返回 true，因为可能是历史记录
            }
        }

        return true;
    }
}

